script:
echo === home dirs ===
sudo ls -la /home/ 2>&1 | grep -i -E 'alej|urich' || echo none
echo === services ===
sudo systemctl list-unit-files 2>&1 | grep -i -E 'alej|urich' || echo none
echo === files ===
sudo find /home /opt /etc/systemd/system -maxdepth 4 -iname '*alej*' -o -iname '*urich*' 2>/dev/null | head -40
echo === vault refs ===
az keyvault secret list --vault-name SDN-YooVault --query "[?contains(name,'alej') || contains(name,'urich')].name" -o tsv 2>&1
echo === catalog search ===
TOK=$(curl -s -X POST 'https://login.microsoftonline.com/sdneurosurgery.com/oauth2/v2.0/token' -H 'Content-Type: application/x-www-form-urlencoded' -d 'client_id=14d82eec-204b-4c2f-b7e8-296a70dab67e' -d 'grant_type=client_credentials' -d 'scope=https://graph.microsoft.com/.default' -d "client_assertion_type=urn:ietf:params:oauth:client-assertion-type:jwt-bearer" 2>/dev/null | python3 -c 'import json,sys;d=json.load(sys.stdin);print(d.get("access_token",""))' 2>/dev/null)
# fallback: managed identity
TOK2=$(curl -s -H 'Metadata:true' 'http://169.254.169.254/metadata/identity/oauth2/token?api-version=2018-02-01&resource=https://graph.microsoft.com' | python3 -c 'import json,sys;print(json.load(sys.stdin).get("access_token",""))')
curl -s -H "Authorization: Bearer $TOK2" "https://graph.microsoft.com/v1.0/appCatalogs/teamsApps?\$filter=distributionMethod eq 'organization'&\$select=id,displayName,externalId" | python3 -c 'import json,sys;d=json.load(sys.stdin); [print(a["displayName"],a["id"]) for a in d.get("value",[]) if "alej" in a["displayName"].lower() or "urich" in a["displayName"].lower()]'
